import{_ as s,o as t,c as r,ag as a}from"./chunks/framework.ETe_P6d1.js";const o="/kaiping-reports/assets/%E5%9B%BE%E4%B8%80.Bg1OwXZK.png",_="/kaiping-reports/assets/%E5%9B%BE%E4%BA%8C.BBBT332d.png",n="/kaiping-reports/assets/%E5%9B%BE%E4%B8%89.BaxmBHxf.png",e="/kaiping-reports/assets/%E5%9B%BE%E5%9B%9B.Bsk1G_su.png",i="/kaiping-reports/assets/%E5%9B%BE%E4%BA%94.BeIcAbTD.png",g="/kaiping-reports/assets/%E5%9B%BE%E5%85%AD.CngqGG-W.png",B="/kaiping-reports/assets/%E5%9B%BE%E4%B8%83.BM4BmFIN.jpg",c="/kaiping-reports/assets/%E5%9B%BE%E5%85%AB.C-sA4wMT.png",m="/kaiping-reports/assets/%E5%9B%BE%E4%B9%9D.BFBTwUH3.png",E="/kaiping-reports/assets/%E5%9B%BE%E4%B9%9D.BFBTwUH3.png",x=JSON.parse('{"title":"","description":"","frontmatter":{},"headers":[],"relativePath":"reports/徐嘉若/徐嘉若开平近代建筑调研报告——基于装饰符号与文化表达的中西建筑对话研究.md","filePath":"reports/徐嘉若/徐嘉若开平近代建筑调研报告——基于装饰符号与文化表达的中西建筑对话研究.md"}'),l={name:"reports/徐嘉若/徐嘉若开平近代建筑调研报告——基于装饰符号与文化表达的中西建筑对话研究.md"};function d(h,p,k,f,u,T){return t(),r("div",null,[...p[0]||(p[0]=[a('<p><strong>开平近代建筑调研报告</strong></p><p><strong>——基于装饰符号与文化表达的中西建筑对话研究</strong></p><p><strong>一、引言：从装饰现象到文化机制的追问</strong></p><p>开平地区近代建筑（以碉楼、骑楼及侨乡民居为代表）是中国近代社会转型与华侨文化交融的重要物质载体。这类建筑在形态上呈现出显著的中西融合特征，尤其体现在立面装饰、构件语汇与材料表达等方面。</p><p>然而，在实际观察中可以发现一个值得进一步探讨的问题：这些装饰元素究竟是形式层面的审美叠加，还是承载了更深层的文化结构与空间逻辑？基于此，本文以“装饰符号与文化表达”为核心视角，提出以下研究问题：</p><p>在开平近代建筑中，装饰符号如何从视觉形式转化为文化表达？中西建筑元素的融合，是简单拼贴，还是形成了一种具有在地性的建筑语言系统？</p><p>为避免泛化分析，本文选取两个具体研究方向展开：</p><p>1.中西建筑文化的对话机制</p><p>2.遗产保护背景下的装饰表达与活态传承并</p><p>通过对塘口碉楼与赤坎骑楼街的对比分析，从空间、材料与界面等环境设计维度进行深入探讨。</p><p><strong>二、案例分析：不同空间类型中的装饰表达差异</strong></p><p>2.1 塘口碉楼：防御空间中的象征性装饰表达</p><p>碉楼作为侨乡特殊历史背景下的产物，其首要功能为防御与居住。然而，在满足安全需求的前提下，其立面却呈现出高度装饰化与西方化的视觉特征。从实地调研来看，其装饰表现具有以下特点：</p><p>1、顶部常采用山花、券拱、罗马柱式等西方古典语汇</p><p>2、立面局部使用灰塑装饰（植物纹样、几何纹样）</p><p>3、整体构图趋于对称，强调竖向比例</p><p>4、材料多为砖混与水泥抹灰，但模拟石材质感</p><p><img src="'+o+'" alt="图1：塘口碉楼立面与顶部装饰"></p><p><img src="'+_+'" alt="图2：塘口碉楼立面与顶部装饰"></p><p><img src="'+n+'" alt="图3：开平中坚楼特写"></p><p><img src="'+e+'" alt="图4：碉楼中西元素叠加墙面图"></p><p>从环境设计角度分析，碉楼的装饰并非独立存在，而是与其空间属性形成关联：</p><p>1、垂直空间强化视觉识别性：装饰集中于顶部，增强远距离可识别性</p><p>2、封闭空间中的外向表达：在内部防御性较强的前提下，通过立面装饰对外进行文化表达</p><p>3、身份象征的空间化呈现：装饰成为侨乡阶层与经济能力的可视化媒介</p><p>因此，碉楼的装饰不仅是审美附加，更是一种结合空间结构、社会身份与文化认同的综合表达系统。</p><p>2.2 赤坎骑楼：商业街区中的界面化装饰系统</p><p>与碉楼的防御属性不同，骑楼建筑属于典型的商业空间类型，其装饰逻辑更强调公共性与连续性。实地调研显示，骑楼装饰呈现出如下特征：</p><p>1、连续拱廊形成灰空间界面，强化街道空间的整体性</p><p>2、柱式与券拱被简化处理，适应商业尺度</p><p>3、装饰主要集中于二层以上立面</p><p>4、建筑装饰与店招、广告系统形成叠合关系</p><p><img src="'+i+'" alt="图5：赤坎骑楼街整体空间界面"></p><p><img src="'+g+'" alt="图6：骑楼立面与商业招牌关系"></p><p><img src="'+B+'" alt="图7：立面装饰分析图"></p><p>从环境设计视角分析，骑楼的装饰具有明显的“界面属性”：</p><p>1、构建街道空间秩序：通过重复的拱廊与柱列形成节奏感</p><p>2、增强步行体验：灰空间提供遮阳避雨功能，提升舒适性</p><p>3、整合视觉信息系统：装饰与商业标识共同构成街道视觉环境</p><p>相较于碉楼的“单体表达”，骑楼更强调装饰作为城市界面的生成机制，而非单一建筑的附属元素。</p><p><strong>三、专业视角：装饰符号的建筑学与环境设计解读</strong></p><p>3.1 文化混杂与建筑语言的再生产</p><p>从建筑史角度看，开平近代建筑属于典型的“文化混杂”现象。然而，其价值不在于简单的元素拼贴，而在于形成了一种新的表达逻辑。具体表现为：</p><p>1、西方构件（柱式、券拱）被嵌入本土结构体系</p><p>2、传统建造方式（灰塑、砖构）承载外来形式</p><p>3、空间组织仍保持中国建筑的层级逻辑</p><p>因此，这种融合应被理解为一种基于在地建造条件与文化经验的“建筑语言再生产”过程。</p><p>3.2 装饰符号的意义建构机制</p><p>借助建筑符号学理论，可以将装饰视为“意义载体”。在本研究案例中，罗马柱象征着秩序、权威与现代性；券拱表达了开放性与交流属性；灰塑纹样延续着地方文化记忆。</p><p>这些符号并非孤立存在，而是在空间中形成关联，共同构建出一种具有跨文化特征的环境认知系统。</p><p>3.3 材料与建造：从技术到文化的转译</p><p>在调研中可以发现，西方形式多由本土工匠通过传统工艺完成，例如：水泥抹灰模拟石材构件、砖混结构承载古典比例、灰塑替代西式浮雕。</p><p><img src="'+c+'" alt="图8：碉楼中水泥抹灰墙面图"></p><p><img src="'+m+'" alt="图9：灰塑装饰细部特写"></p><p><img src="'+E+'" alt="图10：工艺与材料对比图"></p><p>这一现象说明：文化融合不仅发生在视觉层面，更体现在材料选择与建造逻辑之中。从环境设计角度看，这种“材料转译”直接影响空间的触感、视觉质感与使用体验。</p><h4 id="四、批判性思考-装饰表达在当代语境中的困境" tabindex="-1"><strong>四、批判性思考：装饰表达在当代语境中的困境</strong> <a class="header-anchor" href="#四、批判性思考-装饰表达在当代语境中的困境" aria-label="Permalink to &quot;**四、批判性思考：装饰表达在当代语境中的困境**&quot;">​</a></h4><p>4.1 表层化复制问题</p><p>在部分更新与旅游开发中，装饰符号被简化为视觉元素，表现为：</p><p>1、仅复制形式而忽略结构逻辑</p><p>2、使用不匹配材料导致质感失真</p><p>3、装饰脱离原有空间语境</p><p>这一趋势使装饰从“文化表达”退化为“景观表皮”。</p><p>4.2 活态传承的断裂</p><p>骑楼街区在部分改造后，商业功能趋于单一化（如旅游消费），导致了原有生活方式消失、装饰失去使用语境、空间活力下降。问题的关键不在于“是否保护”，而在于如何维持装饰所依附的社会与空间机制。</p><p>4.3 对环境设计实践的启示</p><p>基于上述问题，可以提出以下设计策略：</p><p>1、强调装饰与空间关系的整体保护，而非孤立构件修复</p><p>2、鼓励新旧对话，通过当代设计延续原有语法</p><p>3、引入复合功能（文化、社区、商业），维持空间活力</p><p>其核心在于保护的不仅是形态，而是装饰生成的逻辑与使用场景。</p><h4 id="五、结论-装饰作为环境文化结构的核心要素" tabindex="-1"><strong>五、结论：装饰作为环境文化结构的核心要素</strong> <a class="header-anchor" href="#五、结论-装饰作为环境文化结构的核心要素" aria-label="Permalink to &quot;**五、结论：装饰作为环境文化结构的核心要素**&quot;">​</a></h4><p>通过对碉楼与骑楼的对比研究，本文得出以下结论：</p><p>1、装饰是空间系统的一部分。它与功能、结构及使用方式共同构成完整的环境表达体系。</p><p>2、开平建筑体现了一种在地化的现代性。其装饰并非简单模仿西方，而是对外来文化的再组织与转译。</p><p>3、中西融合的本质在于“语法重构”。即在本土建造体系中生成新的建筑语言，而非形式拼贴。</p><p>4、遗产保护应聚焦“生成机制”。只有延续装饰与空间、社会之间的关系，才能实现真正的活态传承。</p><p>综上所述，开平近代建筑中的装饰符号，应被视为一种连接文化、空间与建造的综合媒介，其研究对于当代环境设计具有重要启示意义。</p><h4 id="六、附录-调研记录" tabindex="-1"><strong>六、附录：调研记录</strong> <a class="header-anchor" href="#六、附录-调研记录" aria-label="Permalink to &quot;**六、附录：调研记录**&quot;">​</a></h4><p>6.1 摄影记录</p><p>本报告共插入 10张图像资料（含现场照片与分析图），用于支撑研究分析：</p><p>图1-图2：塘口碉楼立面与顶部装饰</p><p>图3：开平中坚楼特写</p><p>图4：碉楼中西元素叠加墙面图</p><p>图5：赤坎骑楼街整体空间界面</p><p>图6：骑楼立面与商业招牌关系</p><p>图7：立面装饰分析图</p><p>图8：碉楼中水泥抹灰墙面图</p><p>图9：灰塑装饰细部特写</p><p>图10：工艺与材料对比图</p><p>6.2 文献资料</p><p>[1]谭金花，广东开平侨乡民国建筑装饰的特点与成因及其社会意义[A]，2013</p><p>[2]张国雄，开平碉楼[M],广东人民出版社，2005</p><p>[3]华侨大学建筑学院，华侨建筑文化研究[M],中国建筑工业出版社，2010</p><p>[4]开平碉楼村落保护与利用研究[M],华南理工大学出版社, 2018</p><p>6.3 调研方法说明</p><p>本研究采用以下方法开展：</p><p>1、实地踏勘与摄影记录</p><p>2、建筑类型对比研究</p><p>3、建筑符号学与文化解读方法</p>',100)])])}const b=s(l,[["render",d]]);export{x as __pageData,b as default};
